/// Global list of CUDA device pointers allocated via cudaMalloc.
/// These are freed before each new allocation to prevent GPU memory leaks.
static GPU_ALLOCATIONS: LazyLock<std::sync::Mutex<Vec<u64>>> =
    LazyLock::new(|| std::sync::Mutex::new(Vec::new()));

/// Track the previous iteration's host pointer that was registered via cudaHostRegister,
/// so it can be unregistered before the next registration. This prevents accumulation
/// of pinned host memory which degrades performance over many iterations.
static LAST_HOST_PTR: LazyLock<std::sync::Mutex<Option<u64>>> =
    LazyLock::new(|| std::sync::Mutex::new(None));

/// Counter to make pinned memory buffer IDs unique across iterations.
/// PyTorch may reuse the same data pointer after GC, causing the daemon
/// to reject duplicate registrations and crash the sender.
static PINNED_COUNTER: LazyLock<std::sync::Mutex<u64>> =
    LazyLock::new(|| std::sync::Mutex::new(0));

/// Free all tracked GPU allocations from prior iterations.
///
/// Called at the start of `pin_and_dma_to_gpu` so each iteration
/// only holds one GPU buffer at a time, preventing the accumulation
/// of leaked GPU memory across iterations.
fn free_old_gpu_allocations(py: Python) -> Result<(), String> {
    let mut allocations = GPU_ALLOCATIONS.lock().unwrap();
    if allocations.is_empty() {
        return Ok(());
    }

    // Build a Python snippet that frees every tracked pointer
    let ptrs: Vec<String> = allocations.iter().map(|p| format!("0x{:x}", p)).collect();
    let code = format!(
        r#"
import ctypes
_lib = ctypes.CDLL('libcudart.so')
_lib.cudaFree.restype = ctypes.c_int
_lib.cudaFree.argtypes = [ctypes.c_void_p]
for _ptr in [{}]:
    if _ptr != 0:
        _lib.cudaFree(ctypes.c_void_p(_ptr))
"#,
        ptrs.join(", ")
    );

    let code_cstr = std::ffi::CString::new(code)
        .map_err(|e| format!("failed to create CString: {}", e))?;
    py.run(code_cstr.as_c_str(), None, None)
        .map_err(|e| format!("failed to free GPU memory: {}", e))?;

    allocations.clear();
    Ok(())
}

/// Register host memory as page-locked, then DMA-transfer to GPU.
///
/// Uses cudaHostRegister to pin memory, then cudaMalloc + cudaMemcpy
/// for full-bandwidth DMA transfer from page-locked host memory to GPU.
///
/// Old GPU allocations from previous iterations are freed first so that
/// only one GPU buffer remains live at any time.
fn pin_and_dma_to_gpu(py: Python, host_ptr: u64, size: usize) -> Result<u64, String> {
    if host_ptr == 0 || size == 0 {
        return Err("Invalid host pointer or size".to_string());
    }

    // Free old GPU allocations before allocating new ones
    free_old_gpu_allocations(py)?;

    // Unregister previous cudaHostRegister to prevent pinned memory accumulation
    let prev_host = LAST_HOST_PTR.lock().unwrap().take();
    let unreg_code = if let Some(prev) = prev_host {
        format!(
            r#"
_prev_host = ctypes.c_void_p({prev})
_lib.cudaHostUnregister(_prev_host)
"#,
            prev = prev
        )
    } else {
        String::new()
    };

    let code = format!(
        r#"
import ctypes

lib = ctypes.CDLL('libcudart.so')

lib.cudaHostRegister.restype = ctypes.c_int
lib.cudaHostRegister.argtypes = [ctypes.c_void_p, ctypes.c_size_t, ctypes.c_uint]

lib.cudaHostUnregister.restype = ctypes.c_int
lib.cudaHostUnregister.argtypes = [ctypes.c_void_p]

lib.cudaMalloc.restype = ctypes.c_int
lib.cudaMalloc.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_size_t]

lib.cudaMemcpy.restype = ctypes.c_int
lib.cudaMemcpy.argtypes = [ctypes.c_void_p, ctypes.c_void_p, ctypes.c_size_t, ctypes.c_int]

lib.cudaDeviceSynchronize.restype = ctypes.c_int
lib.cudaDeviceSynchronize.argtypes = []

cudaMemcpyHostToDevice = 1

{unreg_code}
err = lib.cudaHostRegister(ctypes.c_void_p({host_ptr}), {size}, 0)
if err != 0 and err != 712:
    raise RuntimeError(f'cudaHostRegister failed: {{err}}')

d_ptr = ctypes.c_void_p()
err = lib.cudaMalloc(ctypes.byref(d_ptr), {size})
if err != 0:
    raise RuntimeError(f'cudaMalloc failed: {{err}}')

err = lib.cudaMemcpy(d_ptr, ctypes.c_void_p({host_ptr}), {size}, cudaMemcpyHostToDevice)
if err != 0:
    lib.cudaFree(d_ptr)
    raise RuntimeError(f'cudaMemcpy failed: {{err}}')

lib.cudaDeviceSynchronize()

result_ptr = d_ptr.value
"#,
        size = size,
        host_ptr = host_ptr,
        unreg_code = unreg_code,
    );

    let code_cstr = std::ffi::CString::new(code)
        .map_err(|e| format!("failed to create CString: {}", e))?;
    let module = PyModule::from_code(py, code_cstr.as_c_str(), c"cuda_dma.py", c"cuda_dma")
        .map_err(|e| format!("CUDA DMA failed: {}", e))?;

    // Read the result from the Python module variable (no stdout capture needed)
    let device_ptr: u64 = module
        .getattr("result_ptr")
        .map_err(|e| format!("failed to get result_ptr: {}", e))?
        .extract()
        .map_err(|e| format!("failed to extract result_ptr: {}", e))?;

    // Track this allocation so it will be freed before the next one
    GPU_ALLOCATIONS.lock().unwrap().push(device_ptr);

    // Track host pointer to unregister it on next call
    *LAST_HOST_PTR.lock().unwrap() = Some(host_ptr);

    Ok(device_ptr)
}

static RUNTIME: LazyLock<Runtime> = LazyLock::new(|| {
    Builder::new_multi_thread()
        .worker_threads(4)
        .enable_all()
        .build()
        .context("Failed to create Tokio runtime")
        .unwrap()
});

/// Consume a Python `logging.LogRecord` and emit a Rust `tracing::Event` instead.
#[pyfunction]
fn host_log<'py>(record: Bound<'py, PyAny>) -> PyResult<()> {
    let level = record.getattr("levelno")?.extract::<u8>()?;
    let message = record.getattr("getMessage")?.call0()?.to_string();
    let pathname = record.getattr("pathname")?.to_string();
    let lineno = record.getattr("lineno")?.to_string();
    let target = record.getattr("name")?.to_string();

    RUNTIME.spawn(async move {
    if level.ge(&40u8) {
        let span = span!(Level::ERROR, "dora.python.log.error", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::ERROR, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&30u8) {
        let span = span!(Level::WARN, "dora.python.log.warn", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::WARN, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&20u8){
        let span = span!(Level::INFO, "dora.python.log.info", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::INFO, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&10u8) {
        let span = span!(Level::DEBUG, "dora.python.log.debug", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::DEBUG, file=pathname, line=lineno, %target, %message);
    } else {
        let span = span!(Level::TRACE, "dora.python.log.trace", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::TRACE, file=pathname, line=lineno, %target, %message);
    }
    });
    Ok(())
}

/// Modifies the Python `logging` module to deliver its log messages to the host `tracing::Subscriber` by default.
/// To achieve this goal, the following changes are made to the module:
/// - A new builtin function `logging.host_log` transcodes `logging.LogRecord`s to `tracing::Event`s. This function
///   is not exported in `logging.__all__`, as it is not intended to be called directly.
/// - A new class `logging.HostHandler` provides a `logging.Handler` that delivers all records to `host_log`.
/// - `logging.basicConfig` is changed to use `logging.HostHandler` by default.
///
/// Since any call like `logging.warn(...)` sets up logging via `logging.basicConfig`, all log messages are now
/// delivered to `crate::host_log`, which will send them to `tracing::event!`.
pub fn setup_logging(py: Python) -> PyResult<()> {
    let logging = py.import("logging")?;
    logging.setattr("host_log", wrap_pyfunction!(host_log, &logging)?)?;
    py.run(
        cr#"
class HostHandler(Handler):
	def __init__(self, level=0):
		super().__init__(level=level)
	
	def emit(self, record):
		host_log(record)

oldBasicConfig = basicConfig

def basicConfig(*pargs, **kwargs):
	if "handlers" not in kwargs:
		kwargs["handlers"] = [HostHandler()]
	else:
		kwargs["handlers"].append(HostHandler())
	if "level" not in kwargs:
		kwargs["level"] = 0

	return oldBasicConfig(*pargs, **kwargs)
"#,
        Some(&logging.dict()),
        None,
    )?;

    let all = logging.index()?;
    all.append("HostHandler")?;

    Ok(())
}
/// The custom node API lets you integrate `dora` into your application.
/// It allows you to retrieve input and send output in any fashion you want.
///
/// Use with:
///
/// ```python
/// from dora import Node
///
/// node = Node()
/// ```
///
/// :type node_id: str, optional
#[pyclass]
#[derive(Dir, Dict, Str, Repr)]
pub struct Node {
    events: Events,
    node: DelayedCleanup<DoraNode>,

    dataflow_id: DataflowId,
    node_id: NodeId,
}

#[pymethods]
impl Node {
    #[new]
    #[pyo3(signature = (node_id=None, daemon_port=None))]
    pub fn new(node_id: Option<String>, daemon_port: Option<u16>) -> eyre::Result<Self> {
        let (node, events) = if let Some(node_id) = node_id {
            if let Some(port) = daemon_port {
                // Explicit port: always use builder with dynamic mode
                DoraNode::builder()
                    .node_id(NodeId::from(node_id))
                    .dynamic()
                    .daemon_port(port)
                    .build()
            } else {
                // No explicit port: try DORA_NODE_CONFIG first, fall back to dynamic
                DoraNode::init_flexible(NodeId::from(node_id))
            }
            .context("Could not setup node from node id. Make sure to have a running dataflow with this dynamic node")?
        } else {
            DoraNode::init_from_env().context("Could not initiate node from environment variable. For dynamic node, please add a node id in the initialization function.")?
        };
        let id = node.id().clone();
        let dataflow_id = node.dataflow_id().clone();
        RUNTIME.spawn(async move {
            let _guard = init_tracing(&id, &dataflow_id).unwrap();
            loop {
                tokio::time::sleep(std::time::Duration::from_secs(1)).await;
            }
        });

        let dataflow_id = *node.dataflow_id();
        let node_id = node.id().clone();
        let node = DelayedCleanup::new(node);
        let cleanup_handle = NodeCleanupHandle {
            _handles: Arc::new(node.handle()),
        };

        Python::with_gil(|py| {
            // Extend the `logging` module to interact with tracing
            setup_logging(py)
        })?;

        Ok(Node {
            events: Events {
                inner: Arc::new(Mutex::new(EventsInner::Dora(events))),
                _cleanup_handle: cleanup_handle,
            },
            dataflow_id,
            node_id,
            node,
        })
    }

    /// `.next()` gives you the next input that the node has received.
    /// It blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return `None` when all senders has been dropped.
    ///
    /// ```python
    /// event = node.next()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub fn next(&self, py: Python, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = py.allow_threads(|| self.events.recv(timeout.map(Duration::from_secs_f32)))?;
        if let Some(event) = event {
            let dict = event
                .to_py_dict(py)
                .context("Could not convert event into a dict")?;
            Ok(Some(dict))
        } else {
            Ok(None)
        }
    }

    /// `.drain()` gives you all available inputs that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// events = node.drain()
    /// for event in events:
    ///     print(event)
    /// ```
    ///
    /// :rtype: list[dict]
    #[allow(clippy::should_implement_trait)]
    pub fn drain(&self, py: Python) -> PyResult<Vec<Py<PyDict>>> {
        let events = self
            .events
            .drain()
            .context("Could not drain events. Channel is closed")?
            .into_iter()
            .map(|event| {
                event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")
                    .unwrap_or_else(|_| PyDict::new(py).into())
            })
            .collect();
        Ok(events)
    }

    /// `.try_recv()` gives you the next input in the queue that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// event = events.try_recv()
    ///     print(event)
    /// ```
    ///
    /// :rtype: dict
    #[allow(clippy::should_implement_trait)]
    pub fn try_recv(&mut self, py: Python) -> PyResult<Option<Py<PyDict>>> {
        Ok(match self.events.try_recv()? {
            Ok(event) => match event.to_py_dict(py) {
                Ok(dict) => Some(dict),
                Err(_) => None,
            },
            Err(_) => None,
        })
    }

    /// Check if there are any buffered events in the event stream.
    ///
    /// :rtype: bool
    #[allow(clippy::should_implement_trait)]
    pub fn is_empty(&self) -> bool {
        self.events.is_empty()
    }

    /// `.recv_async()` gives you the next input that the node has received asynchronously.
    /// It does not blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return an Error if the timeout is reached.
    /// It will return `None` when all senders has been dropped.
    ///
    /// warning::
    ///     This feature is experimental as pyo3 async (rust-python FFI) is still in development.
    ///
    /// ```python
    /// event = await node.recv_async()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub async fn recv_async(&self, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = self
            .events
            .recv_async_timeout(timeout.map(Duration::from_secs_f32))
            .await?;
        if let Some(event) = event {
            // Get python
            Python::with_gil(|py| {
                let dict = event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")?;

                Ok(Some(dict))
            })
        } else {
            Ok(None)
        }
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// Default behaviour is to timeout after 2 seconds.
    ///
    /// :rtype: dict
    pub fn __next__(&self, py: Python) -> PyResult<Option<Py<PyDict>>> {
        self.next(py, None)
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :rtype: dict
    fn __iter__(slf: PyRef<'_, Self>) -> PyRef<'_, Self> {
        slf
    }

    /// `send_output` send data from the node.
    ///
    /// ```python
    /// Args:
    ///    output_id: str,
    ///    data: pyarrow.Array,
    ///    metadata: Option[Dict],
    /// ```
    ///
    /// ex:
    ///
    /// ```python
    /// node.send_output("string", b"string", {"open_telemetry_context": "7632e76"})
    /// ```
    ///
    /// :type output_id: str
    /// :type data: pyarrow.Array
    /// :type metadata: dict, optional
    /// :rtype: None
    #[pyo3(signature = (output_id, data, metadata=None))]
    pub fn send_output(
        &self,
        output_id: String,
        data: PyObject,
        metadata: Option<Bound<'_, PyDict>>,
        py: Python,
    ) -> eyre::Result<()> {
        let parameters = pydict_to_metadata(metadata)?;

        if let Ok(py_bytes) = data.downcast_bound::<PyBytes>(py) {
            let data = py_bytes.as_bytes();
            self.node
                .get_mut()
                .send_output_bytes(output_id.into(), parameters, data.len(), data)
                .wrap_err("failed to send output")?;
        } else if let Ok(arrow_array) = arrow::array::ArrayData::from_pyarrow_bound(data.bind(py)) {
            self.node.get_mut().send_output(
                output_id.into(),
                parameters,
                arrow::array::make_array(arrow_array),
            )?;
        } else {
            eyre::bail!("invalid `data` type, must by `PyBytes` or arrow array")
        }

        Ok(())
    }

    /// Returns the full dataflow descriptor that this node is part of.
    ///
    /// This method returns the parsed dataflow YAML file.
    ///
    /// :rtype: dict
    pub fn dataflow_descriptor(&self, py: Python) -> eyre::Result<PyObject> {
        Ok(
            pythonize::pythonize(py, &self.node.get_mut().dataflow_descriptor()?)
                .map(|x| x.unbind())?,
        )
    }

    /// Returns the node configuration.
    ///
    /// :rtype: dict
    pub fn node_config(&self, py: Python) -> eyre::Result<PyObject> {
        Ok(pythonize::pythonize(py, &self.node.get_mut().node_config()).map(|x| x.unbind())?)
    }

    /// Returns the dataflow id.
    ///
    /// :rtype: str
    pub fn dataflow_id(&self) -> String {
        self.dataflow_id.to_string()
    }

    /// Merge an external event stream with dora main loop.
    /// This currently only work with ROS2.
    ///
    /// :type subscription: dora.Ros2Subscription
    /// :rtype: None
    pub fn merge_external_events(&self, subscription: &mut Ros2Subscription) -> eyre::Result<()> {
        let subscription = subscription.into_stream()?;
        let stream = futures::stream::poll_fn(move |cx| {
            let s = subscription.as_stream().map(|item| {
                match item.context("failed to read ROS2 message") {
                    Ok((value, _info)) => Python::with_gil(|py| {
                        value
                            .to_pyarrow(py)
                            .context("failed to convert value to pyarrow")
                            .unwrap_or_else(|err| err_to_pyany(err, py))
                    }),
                    Err(err) => Python::with_gil(|py| err_to_pyany(err, py)),
                }
            });
            futures::pin_mut!(s);
            s.poll_next_unpin(cx)
        });

        // take out the event stream and temporarily replace it with a dummy
        let mut inner = self.events.inner.blocking_lock();
        let events = std::mem::replace(
            &mut *inner,
            EventsInner::Merged(Box::new(futures::stream::empty())),
        );
        // update self.events with the merged stream
        *inner = EventsInner::Merged(Box::new(events.merge_external_send(Box::pin(stream))));

        Ok(())
    }

    /// Register pinned memory with the daemon.
    ///
    /// :param pinned_ptr: pyarrow array containing pointer to CPU tensor
    /// :param metadata: dictionary with tensor size, dtype, shape
    /// :rtype: pyarrow array containing shared memory identifier
    #[pyo3(signature = (pinned_ptr, metadata), name = "register_pinned_memory")]
    pub fn register_pinned_memory_internal(
        &self,
        pinned_ptr: PyObject,
        metadata: &Bound<'_, PyDict>,
        py: Python,
    ) -> eyre::Result<PyObject> {
        // Extract pointer value from pyarrow array
        let array_data_result = arrow::array::ArrayData::from_pyarrow_bound(pinned_ptr.bind(py));
        let array_data =
            array_data_result.wrap_err("failed to convert pinned_ptr to arrow array")?;
        let array = arrow::array::make_array(array_data);

        // The array should contain a single integer (pointer value)
        let ptr_value = if let Some(int64_array) =
            array.as_any().downcast_ref::<arrow::array::Int64Array>()
        {
            if int64_array.len() != 1 {
                eyre::bail!(
                    "expected Int64 array with exactly one element, got {}",
                    int64_array.len()
                );
            }
            let val = int64_array.value(0) as u64;
            val
        } else if let Some(int32_array) = array.as_any().downcast_ref::<arrow::array::Int32Array>()
        {
            if int32_array.len() != 1 {
                eyre::bail!(
                    "expected Int32 array with exactly one element, got {}",
                    int32_array.len()
                );
            }
            let val = int32_array.value(0) as u64;
            val
        } else {
            eyre::bail!(
                "pinned_ptr must be an integer array (Int32 or Int64), got {:?}",
                array.data_type()
            )
        };

        // Extract size from metadata
        let size: usize = metadata
            .get_item("size")
            .wrap_err("metadata missing 'size' key")?
            .unwrap()
            .extract()
            .wrap_err("failed to extract size as usize")?;

        // Validate inputs before creating shared memory
        if ptr_value == 0 {
            eyre::bail!("Invalid source pointer (NULL)");
        }
        if size == 0 || size > 1024 * 1024 * 1024 {
            eyre::bail!("Invalid size: {} bytes", size);
        }

        let shmem_conf = ShmemConf::new().size(size).writable(true);
        let mut shmem = shmem_conf
            .create()
            .wrap_err("failed to create shared memory")?;
        let shmem_name = shmem.get_os_id().to_string();

        if shmem.as_ptr().is_null() {
            eyre::bail!("Shared memory pointer is NULL");
        }

        // Copy data from pointer to shared memory
        unsafe {
            let src_ptr = ptr_value as *const u8;
            let slice = shmem.as_slice_mut();
            let dst_ptr = slice.as_mut_ptr();
            std::ptr::copy_nonoverlapping(src_ptr, dst_ptr, size);
        }

        // Don't mem::forget — set owner=false so Drop does munmap+close
        // but skips shm_unlink, keeping the name alive for the receiver.
        // This prevents accumulation of mmap'd shmem regions across iterations.
        shmem.set_owner(false);

        // Tag metadata with shared memory name and source pointer for the receiver
        let py_shmem_name = PyString::new(py, &shmem_name);
        metadata.set_item("shared_memory_name", py_shmem_name)?;
        metadata.set_item("ptr", ptr_value)?;

        // Convert metadata dict to MetadataParameters for daemon communication
        let mut parameters = MetadataParameters::new();
        for (key, value) in metadata.iter() {
            let key_str = key.to_string();

            if value.is_exact_instance_of::<PyBool>() {
                let val: bool = value.extract()?;
                parameters.insert(key_str, Parameter::Bool(val));
            } else if value.is_instance_of::<PyInt>() {
                let val: i64 = value.extract()?;
                parameters.insert(key_str, Parameter::Integer(val));
            } else if value.is_instance_of::<PyFloat>() {
                let val: f64 = value.extract()?;
                parameters.insert(key_str, Parameter::Float(val));
            } else if value.is_instance_of::<PyString>() {
                let val: String = value.extract()?;
                parameters.insert(key_str, Parameter::String(val));
            } else if let Ok(list) = value.downcast::<PyList>() {
                let mut int_list = Vec::new();
                let mut all_ints = true;
                for item in list.iter() {
                    if let Ok(val) = item.extract::<i64>() {
                        int_list.push(val);
                    } else {
                        all_ints = false;
                        break;
                    }
                }
                if all_ints {
                    parameters.insert(key_str, Parameter::ListInt(int_list));
                } else if let Ok(s) = value.str() {
                    parameters.insert(key_str, Parameter::String(s.to_string()));
                }
            } else if let Ok(s) = value.str() {
                parameters.insert(key_str, Parameter::String(s.to_string()));
            }
        }

        // Create Metadata object with empty type info and current timestamp
        let timestamp = uhlc::HLC::default().new_timestamp();
        let type_info = ArrowTypeInfoExt::empty();
        let metadata_obj = Metadata::from_parameters(timestamp, type_info, parameters);

        // Generate unique buffer ID: pointer + counter
        // (pointer alone can repeat when PyTorch reuses memory after GC)
        let counter = {
            let mut c = PINNED_COUNTER.lock().unwrap();
            *c += 1;
            *c
        };
        let buffer_id = format!("pinned_{:x}_{}", ptr_value, counter);

        // Call DoraNode's register_pinned_memory method
        self.node
            .get_mut()
            .register_pinned_memory(buffer_id.clone(), metadata_obj)
            .wrap_err("failed to register pinned memory with daemon")?;

        // Return buffer ID as a string array
        let buffer_id_array = arrow::array::StringArray::from(vec![buffer_id.clone()]);
        Ok(buffer_id_array.to_data().to_pyarrow(py).unwrap())
    }

    /// Read pinned memory from daemon and transfer to CUDA.
    ///
    /// :param pinned_buffer: pyarrow array containing shared memory identifier
    /// :param free: if True, free the pinned memory after reading
    /// :rtype: dictionary with cuda ptr, size, dtype, shape
    #[pyo3(signature = (pinned_buffer, free=true))]
    pub fn read_pinned_memory(
        &self,
        pinned_buffer: PyObject,
        free: bool,
        py: Python,
    ) -> eyre::Result<PyObject> {
        // Extract shared memory ID from pyarrow array
        let array_data_result = arrow::array::ArrayData::from_pyarrow_bound(pinned_buffer.bind(py));
        let array_data =
            array_data_result.wrap_err("failed to convert pinned_buffer to arrow array")?;
        let array = arrow::array::make_array(array_data);

        // The array should be a binary array containing the shared memory ID
        let shared_memory_id = match array.data_type() {
            DataType::Utf8 => {
                if let Some(string_array) = array.as_any().downcast_ref::<StringArray>() {
                    if string_array.len() != 1 {
                        eyre::bail!(
                            "expected string array with exactly one element, got {}",
                            string_array.len()
                        );
                    }
                    let id = string_array.value(0).to_string();
                    id
                } else {
                    eyre::bail!("failed to downcast Utf8 array to StringArray")
                }
            }
            DataType::Binary => {
                if let Some(binary_array) = array.as_any().downcast_ref::<BinaryArray>() {
                    if binary_array.len() != 1 {
                        eyre::bail!(
                            "expected binary array with exactly one element, got {}",
                            binary_array.len()
                        );
                    }
                    let bytes = binary_array.value(0);
                    String::from_utf8(bytes.to_vec())
                        .wrap_err("shared memory ID is not valid UTF-8")?
                } else {
                    eyre::bail!("failed to downcast Binary array to BinaryArray")
                }
            }
            _ => {
                eyre::bail!(
                    "READ/FREE: pinned_buffer must be a binary or string array, got {:?}",
                    array.data_type()
                )
            }
        };

        // Always read without freeing to avoid race with shared memory deletion
        let metadata = match self.node.get_mut().read_pinned_memory(shared_memory_id.clone(), false) {
            Ok(m) => m,
            Err(_e) => {
                tracing::warn!(
                    "[{}]读取不存在的页锁内存{}",
                    self.node_id, shared_memory_id
                );
                // Return dummy values for read-after-free case
                let ptr_array = arrow::array::Int64Array::from(vec![0i64]);
                let pinned_ptr = ptr_array.to_data().to_pyarrow(py)
                    .map_err(|e| eyre::eyre!("failed to convert to pyarrow: {}", e))?;
                let dict = PyDict::new(py);
                dict.set_item("size", 0).ok();
                let tuple = PyTuple::new(py, &[pinned_ptr, dict.into()])?;
                return Ok(tuple.into());
            }
        };

        // Extract size from Rust metadata parameters for warnings
        let data_size: i64 = metadata
            .parameters
            .get("size")
            .and_then(|p| {
                if let Parameter::Integer(v) = p {
                    Some(*v)
                } else {
                    None
                }
            })
            .unwrap_or(0);
        let dict = metadata_to_pydict(&metadata, py)
            .wrap_err("failed to convert metadata to Python dictionary")?;
        let ptr_value: u64;
        if let Some(shmem_name_obj) = dict.get_item("shared_memory_name")? {
            let shmem_name: String = shmem_name_obj.extract()?;

            // Shared memory may have been unlinked by a prior free; handle gracefully
            let shmem = match ShmemConf::new().os_id(&shmem_name).open() {
                Ok(s) => s,
                Err(_) => {
                    tracing::warn!(
                        "[{}]读取不存在的页锁内存{}",
                        self.node_id, shared_memory_id
                    );
                    let ptr_array = arrow::array::Int64Array::from(vec![0i64]);
                    let pinned_ptr = ptr_array.to_data().to_pyarrow(py).unwrap_or_else(|_|
                        arrow::array::Int64Array::from(vec![0i64]).to_data().to_pyarrow(py).unwrap()
                    );
                    let empty_dict = PyDict::new(py);
                    empty_dict.set_item("size", 0).ok();
                    let tuple = PyTuple::new(py, &[pinned_ptr, empty_dict.into()])?;
                    return Ok(tuple.into());
                }
            };

            let host_ptr = shmem.as_ptr() as u64;

            let size: usize = match dict.get_item("size") {
                Ok(Some(v)) => v.extract::<usize>().unwrap_or(0),
                _ => 0,
            };
            let cuda_result = if size > 0 {
                pin_and_dma_to_gpu(py, host_ptr, size)
            } else {
                Err("size is 0".to_string())
            };

            if let Ok(device_ptr) = cuda_result {
                dict.set_item("ptr", device_ptr as i64).ok();
                dict.set_item("is_cuda", true).ok();
                dict.set_item("device", "cuda").ok();
                ptr_value = device_ptr;
            } else {
                ptr_value = host_ptr;
            }

            // Drop shmem — DMA is complete, no need to keep the mmap alive.
            // munmap + close(fd) happen here but shm_unlink is skipped since
            // this process only opened (did not create) the shared memory.
        } else {
            ptr_value = dict
                .get_item("ptr")
                .wrap_err("metadata dict missing 'ptr' key")?
                .unwrap()
                .extract()
                .wrap_err("failed to extract ptr as u64")?;
        }

        let ptr_array = arrow::array::Int64Array::from(vec![ptr_value as i64]);
        let pinned_ptr = ptr_array.to_data().to_pyarrow(py).unwrap();

        // Free daemon entry if requested
        if free {
            if let Err(_e) = self
                .node
                .get_mut()
                .free_pinned_memory(shared_memory_id.clone())
            {
                tracing::warn!(
                    "[{}]重复释放页锁内存{},size={}",
                    self.node_id, shared_memory_id, data_size
                );
            }
        }

        let tuple = PyTuple::new(py, &[pinned_ptr, dict.into()]);
        let tuple = tuple?;
        Ok(tuple.into())
    }

    /// Free pinned memory registered with daemon.
    ///
    /// :param pinned_buffer: pyarrow array containing shared memory identifier
    /// :rtype: None
    #[pyo3(signature = (pinned_buffer,))]
    pub fn free_pinned_memory(&self, pinned_buffer: PyObject, py: Python) -> eyre::Result<()> {
        // Extract shared memory ID from pyarrow array
        let array_data = arrow::array::ArrayData::from_pyarrow_bound(pinned_buffer.bind(py))
            .wrap_err("failed to convert pinned_buffer to arrow array")?;
        let array = arrow::array::make_array(array_data);

        // The array should be a binary array containing the shared memory ID
        let shared_memory_id =
            if let Some(binary_array) = array.as_any().downcast_ref::<BinaryArray>() {
                if binary_array.len() != 1 {
                    eyre::bail!(
                        "expected binary array with exactly one element, got {}",
                        binary_array.len()
                    );
                }
                let bytes = binary_array.value(0);
                String::from_utf8(bytes.to_vec()).wrap_err("shared memory ID is not valid UTF-8")?
            } else if let Some(string_array) = array.as_any().downcast_ref::<StringArray>() {
                if string_array.len() != 1 {
                    eyre::bail!(
                        "expected string array with exactly one element, got {}",
                        string_array.len()
                    );
                }
                string_array.value(0).to_string()
            } else {
                eyre::bail!(
                    "FREE: pinned_buffer must be a binary or string array, got {:?}",
                    array.data_type()
                )
            };

        let result = self.node.get_mut().free_pinned_memory(shared_memory_id.clone());
        match result {
            Ok(_) => {}
            Err(e) => {
                let err_msg = format!("{:#}", e);
                // Extract size from error message "already freed,size=N"
                let size_str = err_msg.split("size=").nth(1).unwrap_or("0");
                tracing::warn!(
                    "[{}]重复释放页锁内存{},size={}",
                    self.node_id, shared_memory_id, size_str
                );
            }
        }

        Ok(())
    }
}

fn err_to_pyany(err: eyre::Report, gil: Python<'_>) -> Py<PyAny> {
    PyErr::from(err)
        .into_pyobject(gil)
        .unwrap_or_else(|infallible| match infallible {})
        .into_any()
        .unbind()
}

struct Events {
    inner: Arc<Mutex<EventsInner>>,
    _cleanup_handle: NodeCleanupHandle,
}

impl Events {
    fn recv(&self, timeout: Option<Duration>) -> PyResult<Option<PyEvent>> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                match timeout {
                    Some(timeout) => events.recv_timeout(timeout).map(MergedEvent::Dora),
                    None => events.recv().map(MergedEvent::Dora),
                }
            }
            EventsInner::Merged(events) => futures::executor::block_on(events.next()),
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    fn try_recv(&self) -> PyResult<Result<PyEvent, TryRecvError>> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                events.try_recv().map(MergedEvent::Dora)
            }
            EventsInner::Merged(_events) => {
                todo!("try_recv on external event stream is not yet implemented!")
            }
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    async fn recv_async_timeout(&self, timeout: Option<Duration>) -> PyResult<Option<PyEvent>> {
        let mut inner = self.inner.lock().await;
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                match timeout {
                    Some(timeout) => events
                        .recv_async_timeout(timeout)
                        .await
                        .map(MergedEvent::Dora),
                    None => events.recv_async().await.map(MergedEvent::Dora),
                }
            }
            EventsInner::Merged(events) => events.next().await,
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    fn drain(&self) -> Option<Vec<PyEvent>> {
        let mut inner = self.inner.blocking_lock();
        match &mut *inner {
            EventsInner::Dora(events) => match events.drain() {
                Some(items) => {
                    return Some(
                        items
                            .into_iter()
                            .map(MergedEvent::Dora)
                            .map(|event| PyEvent { event })
                            .collect(),
                    );
                }
                None => return None,
            },
            EventsInner::Merged(_events) => {
                todo!("Draining external event is not yet implemented!")
            }
        };
    }

    fn is_empty(&self) -> bool {
        let inner = self.inner.blocking_lock();
        match &*inner {
            EventsInner::Dora(events) => events.is_empty(),
            EventsInner::Merged(_events) => {
                todo!("is_empty on external event stream is not yet implemented!")
            }
        }
    }
}

#[allow(clippy::large_enum_variant)]
enum EventsInner {
    Dora(EventStream),
    Merged(Box<dyn Stream<Item = MergedEvent<PyObject>> + Unpin + Send + Sync>),
}

impl<'a> MergeExternalSend<'a, PyObject> for EventsInner {
    type Item = MergedEvent<PyObject>;

    fn merge_external_send(
        self,
        external_events: impl Stream<Item = PyObject> + Unpin + Send + Sync + 'a,
    ) -> impl Stream<Item = Self::Item> + Unpin + Send + Sync + 'a {
        let stream: Box<dyn Stream<Item = Self::Item> + Unpin + Send + Sync + 'a> = match self {
            EventsInner::Dora(events) => Box::new(events.merge_external_send(external_events)),
            EventsInner::Merged(events) => {
                let merged = events.merge_external_send(external_events);
                Box::new(merged.map(|event| match event {
                    MergedEvent::Dora(e) => MergedEvent::Dora(e),
                    MergedEvent::External(e) => MergedEvent::External(e.flatten()),
                }))
            }
        };
        stream
    }
}

impl Node {
    pub fn id(&self) -> String {
        self.node_id.to_string()
    }
}

/// Start a runtime for Operators
///
/// :rtype: None
#[pyfunction]
pub fn start_runtime() -> eyre::Result<()> {
    dora_runtime::main().wrap_err("Dora Runtime raised an error.")
}

pub fn resolve_dataflow(dataflow: String) -> eyre::Result<PathBuf> {
    let dataflow = if source_is_url(&dataflow) {
        // try to download the shared library
        let target_path = current_dir().context("Could not access the current dir")?;
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .context("tokio runtime failed")?;
        rt.block_on(async { download_file(&dataflow, &target_path).await })
            .wrap_err("failed to download dataflow yaml file")?
    } else {
        PathBuf::from(dataflow)
    };
    Ok(dataflow)
}

/// Build a Dataflow, exactly the same way as `dora build` command line tool.
///
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type coordinator_addr: str, optional
/// :type coordinator_port: int, optional
/// :type force_local: bool, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, coordinator_addr=None, coordinator_port=None, force_local=false))]
pub fn build(
    dataflow_path: String,
    uv: Option<bool>,
    coordinator_addr: Option<String>,
    coordinator_port: Option<u16>,
    force_local: bool,
) -> eyre::Result<()> {
    dora_cli::build(
        dataflow_path,
        coordinator_addr.map(|addr| addr.parse().unwrap()),
        coordinator_port,
        uv.unwrap_or_default(),
        force_local,
    )
}

/// Run a Dataflow, exactly the same way as `dora run` command line tool.
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type stop_after: float, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, stop_after=None))]
pub fn run(dataflow_path: String, uv: Option<bool>, stop_after: Option<f64>) -> eyre::Result<()> {
    use dora_cli::Executable;

    let stop_after_duration = stop_after.map(std::time::Duration::from_secs_f64);
    let mut run = dora_cli::RunCommand::new(dataflow_path);
    if let Some(uv) = uv {
        run.uv = uv;
    }
    if let Some(duration) = stop_after_duration {
        run.stop_after = Some(duration);
    }
    let rt = tokio::runtime::Builder::new_multi_thread()
        .enable_all()
        .build()
        .context("tokio runtime failed")?;
    rt.block_on(run.execute())
}

#[pymodule]
fn dora(_py: Python, m: Bound<'_, PyModule>) -> PyResult<()> {
    dora_ros2_bridge_python::create_dora_ros2_bridge_module(&m)?;

    m.add_function(wrap_pyfunction!(start_runtime, &m)?)?;
    m.add_function(wrap_pyfunction!(run, &m)?)?;
    m.add_function(wrap_pyfunction!(build, &m)?)?;
    m.add_class::<Node>()?;
    m.setattr("__version__", env!("CARGO_PKG_VERSION"))?;
    m.setattr("__author__", "Dora-rs Authors")?;

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use shared_memory_extended::ShmemConf;

    #[test]
    fn test_shmem_creation() {
        // Test that ShmemConf can create and write to shared memory
        let size = 8000;
        let shmem_conf = ShmemConf::new().size(size).writable(true);

        let mut shmem = shmem_conf.create().expect("failed to create shared memory");

        // Write to shared memory
        let slice = unsafe { shmem.as_slice_mut() };
        slice[0] = 0x42;
        assert_eq!(slice[0], 0x42);

        // Write pattern
        for i in 0..size.min(100) {
            slice[i] = (i % 256) as u8;
        }

        // Read back
        for i in 0..size.min(100) {
            assert_eq!(slice[i], (i % 256) as u8);
        }
    }
}
